import React, { useRef, useEffect, useState } from 'react';
// Импортируем Map, YMaps и useYMaps для ручной инициализации объектов
import { YMaps, Map, useYMaps } from '@pbe/react-yandex-maps'; 

const CENTER_COORDS = [55.7196, 37.6366]; 
const apiKey = ''; // Оставьте пустым, если не используете

// --- Вспомогательный компонент для надежной инициализации метки ---
// Этот компонент отвечает только за создание объекта карты и ручное добавление Placemark.
const PlacemarkCreator = () => {
    // 1. Получаем доступ к экземпляру API Яндекса. Запрашиваем только конструктор Placemark.
    const ymaps = useYMaps(['Placemark']); 
    // 2. Ссылка на DOM-элемент карты (Map)
    const mapRef = useRef(null); 
    // 3. Флаг для предотвращения повторного добавления метки
    const [isPlacemarkAdded, setIsPlacemarkAdded] = useState(false);

    useEffect(() => {
        // Проверяем, что API Яндекса загружен, у нас есть ссылка на карту и метка еще не добавлена
        if (ymaps && mapRef.current && !isPlacemarkAdded) {

            // Защита от потенциальной ошибки (хотя Placemark должен быть загружен)
            if (!ymaps.Placemark) return;

            // 4. Создаем новый объект метки Яндекса (не React-компонент)
            const placemark = new ymaps.Placemark(CENTER_COORDS, {
                hintContent: "Наш адрес: Дубининская ул., 96"
            }, {
                preset: 'islands#darkGreenDotIcon' // Стиль метки
            });

            // 5. Добавляем метку на карту
            mapRef.current.geoObjects.add(placemark);
            setIsPlacemarkAdded(true);
        }
    // Зависимости: ymaps (API), mapRef.current (сам объект карты)
    }, [ymaps, isPlacemarkAdded]); 

    // Эффект очистки: удаляем метку при демонтаже или повторном рендеринге (важно для StrictMode)
    useEffect(() => {
        return () => {
            if (mapRef.current) {
                // Удаление всех объектов при демонтаже (для корректной работы в StrictMode)
                mapRef.current.geoObjects.removeAll();
                setIsPlacemarkAdded(false);
            }
        };
    }, []);


    return (
        // Map инициализируется без дочерних элементов Placemark, 
        // так как они добавляются вручную выше
        <Map 
            instanceRef={mapRef} // Передаем ссылку на Map
            defaultState={{ 
                center: CENTER_COORDS, 
                zoom: 16, 
                controls: ["zoomControl", "fullscreenControl", "rulerControl"] 
            }}
            width="100%"
            height="100%"
        />
    );
};
// --- Конец PlacemarkCreator ---


const YandexMapComponent = () => {
    return (
        // YMaps загружает API
        <YMaps query={{ apikey: apiKey, load: 'Map,Placemark' }}>
            {/* Рендерим компонент, который безопасно добавляет метку */}
            <PlacemarkCreator />
        </YMaps>
    );
};

export default YandexMapComponent;
